/**
 * Rate Limiting Check Edge Function
 * 
 * Checks and enforces rate limits using Upstash Redis.
 * Runs as middleware before main request handling.
 * 
 * POST /functions/v1/rate-limit-check
 * {
 *   "identifier": "user_id_or_ip",
 *   "limitType": "login" | "signup" | "api" | "anon" | "passwordReset"
 * }
 */

import { serve } from "https://deno.land/std@0.208.0/http/server.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization",
};

interface RateLimitConfig {
  maxRequests: number;
  windowSeconds: number;
}

const limitConfigs: Record<string, RateLimitConfig> = {
  login: { maxRequests: 5, windowSeconds: 900 }, // 5 per 15 min (brute force protection)
  signup: { maxRequests: 5, windowSeconds: 3600 }, // 5 per hour (allow retries with different emails)
  passwordReset: { maxRequests: 3, windowSeconds: 3600 }, // 3 per hour (abuse prevention)
  chat: { maxRequests: 20, windowSeconds: 900 }, // 20 per 15 min (spam prevention, allows conversation)
  api: { maxRequests: 300, windowSeconds: 3600 }, // 300 per hour (active dashboard usage)
  anon: { maxRequests: 30, windowSeconds: 3600 }, // 30 per hour (guest usage)
};

interface RateLimitRequest {
  identifier: string;
  limitType: string;
}

async function checkRedisLimit(
  redisUrl: string,
  redisToken: string,
  key: string,
  maxRequests: number,
  windowSeconds: number
): Promise<{ success: boolean; limit: number; remaining: number; reset: number }> {
  const response = await fetch(
    `${redisUrl}/incr/${key}`,
    {
      headers: {
        "Authorization": `Bearer ${redisToken}`,
      },
    }
  );

  if (!response.ok) {
    throw new Error("Redis error");
  }

  const data = await response.json();
  const currentCount = data.result;

  // Set expiration on first request
  if (currentCount === 1) {
    await fetch(`${redisUrl}/expire/${key}/${windowSeconds}`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${redisToken}`,
      },
    });
  }

  const remaining = Math.max(0, maxRequests - currentCount);
  const isLimited = currentCount > maxRequests;
  const resetTimestamp = Date.now() + (windowSeconds * 1000);

  return {
    success: !isLimited,
    limit: maxRequests,
    remaining,
    reset: resetTimestamp,
  };
}

serve(async (req) => {
  // Handle CORS preflight
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  if (req.method !== "POST") {
    return new Response(
      JSON.stringify({ error: "Method not allowed" }),
      { status: 405, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }

  try {
    const payload = (await req.json()) as RateLimitRequest;

    if (!payload.identifier || !payload.limitType) {
      return new Response(
        JSON.stringify({ error: "Missing identifier or limitType" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const config = limitConfigs[payload.limitType];
    if (!config) {
      return new Response(
        JSON.stringify({ error: `Unknown limitType: ${payload.limitType}` }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const redisUrl = Deno.env.get("UPSTASH_REDIS_REST_URL");
    const redisToken = Deno.env.get("UPSTASH_REDIS_REST_TOKEN");

    if (!redisUrl || !redisToken) {
      console.warn("Redis not configured, allowing request");
      return new Response(
        JSON.stringify({
          success: true,
          limit: config.maxRequests,
          remaining: config.maxRequests,
          reset: Date.now() + (config.windowSeconds * 1000),
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const key = `ratelimit:${payload.limitType}:${payload.identifier}`;
    const result = await checkRedisLimit(
      redisUrl,
      redisToken,
      key,
      config.maxRequests,
      config.windowSeconds
    );

    if (!result.success) {
      const retryAfterSeconds = Math.ceil((result.reset - Date.now()) / 1000);
      return new Response(
        JSON.stringify({
          success: false,
          limit: result.limit,
          remaining: result.remaining,
          reset: result.reset,
          error: "Rate limit exceeded",
        }),
        {
          status: 429,
          headers: {
            ...corsHeaders,
            "Content-Type": "application/json",
            "Retry-After": String(retryAfterSeconds),
          },
        }
      );
    }

    return new Response(
      JSON.stringify({
        success: true,
        limit: result.limit,
        remaining: result.remaining,
        reset: result.reset,
      }),
      { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    console.error("Rate limit check error:", error);
    return new Response(
      JSON.stringify({ error: "Rate limit check failed" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

/**
 * Shared database utilities for Edge Functions
 */

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

export function createSupabaseClient() {
  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const supabaseServiceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

  if (!supabaseUrl || !supabaseServiceKey) {
    throw new Error("Missing Supabase credentials");
  }

  return createClient(supabaseUrl, supabaseServiceKey);
}

export function createSupabaseUserClient(token: string) {
  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY");

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error("Missing Supabase credentials");
  }

  return createClient(supabaseUrl, supabaseAnonKey, {
    global: {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    },
  });
}

/**
 * Shared error handling for Edge Functions
 */

export class EdgeFunctionError extends Error {
  constructor(
    public statusCode: number,
    message: string,
    public details?: Record<string, unknown>
  ) {
    super(message);
    this.name = "EdgeFunctionError";
  }
}

export function handleError(error: unknown) {
  console.error("Error:", error);

  if (error instanceof EdgeFunctionError) {
    return new Response(
      JSON.stringify({
        error: error.message,
        details: error.details,
      }),
      {
        status: error.statusCode,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  if (error instanceof Error) {
    return new Response(
      JSON.stringify({
        error: error.message,
      }),
      {
        status: 500,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  return new Response(
    JSON.stringify({
      error: "Internal server error",
    }),
    {
      status: 500,
      headers: { "Content-Type": "application/json" },
    }
  );
}

export async function withRetry<T>(
  fn: () => Promise<T>,
  maxRetries = 3,
  delayMs = 1000
): Promise<T> {
  let lastError: Error | unknown;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      if (i < maxRetries - 1) {
        await new Promise((resolve) => setTimeout(resolve, delayMs * Math.pow(2, i)));
      }
    }
  }

  throw lastError;
}

/**
 * Shared types for Edge Functions
 */

export interface EdgeFunctionRequest extends Request {
  auth?: {
    user?: {
      id: string;
      email: string;
      [key: string]: unknown;
    };
  };
}

export interface EmailPayload {
  to: string | string[];
  subject: string;
  template?: string;
  templateData?: Record<string, unknown>;
  html?: string;
  text?: string;
  from?: string;
  replyTo?: string;
  tags?: string[];
}

export interface RateLimitPayload {
  identifier: string;
  limitType: "login" | "signup" | "api" | "anon" | "passwordReset";
}

export interface WebhookPayload {
  type: string;
  [key: string]: unknown;
}

export interface ChatPayload {
  messages: Array<{
    role: "user" | "assistant" | "system";
    content: string;
  }>;
  context?: Record<string, unknown>;
  model?: "groq" | "openai";
}

export interface TurnstilePayload {
  token: string;
  remoteIp?: string;
}
